/**
 * Parses a packet from a buffer.
 * 
 * The buffer contains:
 * - A 4-byte big-endian unsigned integer N representing the count of records.
 * - N records, each 8 bytes in length.
 * 
 * @param buf The source buffer.
 * @param len The length of the buffer.
 * @return A pointer to an allocated array of N 8-byte records, or NULL on error.
 *         The caller is responsible for freeing the returned memory.
 */
uint8_t* parse_packet(const uint8_t *buf, size_t len) {
    // Basic input validation
    if (buf == NULL || len < 4) {
        return NULL;
    }

    // Read 4-byte big-endian count N.
    // We cast to uint32_t to ensure the bitwise shifts behave correctly 
    // regardless of whether the architecture's default int is 16 or 32 bits.
    uint32_t n = ((uint32_t)buf[0] << 24) |
                  ((uint32_t)buf[1] << 16) |
                  ((uint32_t)buf[2] << 8)  |
                  ((uint32_t)buf[3]);

    // Requirement: Allocate an array of N records.
    // If N is 0, the behavior is often ambiguous; returning NULL is standard for "no records".
    if (n == 0) {
        return NULL;
    }

    /* 
     * Security/Safety Checks:
     * 1. Check for multiplication overflow: n * 8 must not exceed the capacity of size_t.
     * 2. Check for addition overflow: 4 + (n * 8) must not exceed the capacity of size_t.
     * 3. Check for buffer overflow: len must be at least 4 + (n * 8).
     * 
     * On a 32-bit target, SIZE_MAX is 0xFFFFFFFF. 
     * We check if n exceeds (SIZE_MAX - 4) / 8 to prevent both allocation 
     * and buffer length overflows.
     */
    if (n > (SIZE_MAX - 4) / 8) {
        return NULL;
    }

    size_t total_record_size = (size_t)n * 8;

    // Ensure the buffer is large enough to contain the header and all records.
    if (len < (4 + total_record_size)) {
        return NULL;
    }

    // Allocate the array of records.
    uint8_t *records = (uint8_t *)malloc(total_record_size);
    if (records == NULL) {
        return NULL;
    }

    // Copy the records out of the buffer.
    // The records start at offset 4 (immediately after the count N).
    memcpy(records, buf + 4, total_record_size);

    return records;
}
