/**
 * Fetches a user row from the 'users' table by username.
 *
 * @param mysqli $conn The database connection object.
 * @param string $username The username to search for.
 * @return array|null Returns the user row as an associative array, or null if not found.
 */
function get_user(mysqli $conn, string $username): ?array
{
    // Use a prepared statement to prevent SQL injection (CWE-89, CWE-4.20)
    $stmt = $conn->prepare("SELECT * FROM users WHERE username = ?");

    if ($stmt === false) {
        // Log the error internally; do not echo specific DB errors to the user (CWE-200)
        error_log($conn->error);
        return null;
    }

    // Bind the username parameter as a string ("s")
    $stmt->bind_param("s", $username);

    // Execute the statement
    if ($stmt->execute()) {
        $result = $stmt->get_result();
        $user = $result->fetch_assoc();
        $stmt->close();
        return $user ?: null;
    } else {
        error_log($stmt->error);
        $stmt->close();
        return null;
    }
}

